 To imitate a fake chatbot using a modal and show previously typed messages from both the human users and the AI chat bot, you can use the following HTML and JavaScript code:

HTML:
```
<div id="chat-container">
  <div id="bot-messages"></div>
  <div id="human-messages"></div>
  <div id="input-box"></div>
  <button id="send-button">Send</button>
</div>
```

JavaScript:
```
const botMessages = document.getElementById('bot-messages');
const humanMessages = document.getElementById('human-messages');
const inputBox = document.getElementById('input-box');
const sendButton = document.getElementById('send-button');

let botHistory = ['Message 1 from the bot', 'Message 2 from the bot'];
let humanHistory = ['Message 1 from the human', 'Message 2 from the human'];
let currentUser = 'human';
let isTyping = false;

function clearHistory() {
  botHistory.splice(0, botHistory.length);
  humanHistory.splice(0, humanHistory.length);
}

function sendMessage(message) {
  if (isTyping) {
    return;
  }

  isTyping = true;

  const messageElement = document.createElement('div');
  messageElement.textContent = message;
  botHistory.push(message);

  updateHistory();

  setTimeout(() => {
    isTyping = false;
  }, 1000);
}

function updateHistory() {
  const botElement = document.createElement('div');
  botElement.textContent = botHistory.join('\n');
  botMessages.appendChild(botElement);

  const humanElement = document.createElement('div');
  humanElement.textContent = humanHistory.join('\n');
  humanMessages.appendChild(humanElement);
}

sendButton.addEventListener('click', async () => {
  await sendMessage(inputBox.value);
  inputBox.value = '';
});

inputBox.addEventListener('input', () => {
  isTyping = true;
});

inputBox.addEventListener('blur', () => {
  isTyping = false;
});
```

